#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int i = 0; i < T; ++i) {
        double R;
        if (scanf("%lf", &R) != 1) return 0;
        double area = 3.14 * R * R;
        printf("%.1f\n", area);
    }
    return 0;
}

